/**
 * The Cartograph — vision/charge/piece decomposition-ladder apparatus.
 *
 * Stands up the data-and-typed-API substrate for the four-level
 * decomposition ladder:
 *
 *   vision (top, patron-owned, long-lived)
 *     → charge (first decomposition, the unit of patron walkthrough)
 *       → piece (recursive, internal organization, self-nesting)
 *         → mandate (existing leaf where rigs attach)
 *
 * Three writ types (`vision`, `charge`, `piece`) are contributed to the
 * Clerk via `clerk.registerWritType` from `start()`. Each type uses a
 * six-state mandate-clone lifecycle without `childrenBehavior` cascade —
 * patron-walkthrough semantics are coordinated by the typed API and
 * downstream consumers, not by registry-side cascade rules.
 *
 * Three companion books (`visions`, `charges`, `pieces`) under owner id
 * `cartograph` shadow each writ with a typed companion document. The
 * doc's primary key is the writ id one-for-one. Vision text lives on
 * `writ.body`; the companion docs carry typed metadata only.
 *
 * The typed API is the **only** layer that enforces the ladder's parent
 * invariants — vision has no parent, `charge.parentId` must be a vision,
 * `piece.parentId` must be a charge or piece. Raw `clerk.post({ type:
 * 'vision' })` continues to succeed without parent-type checks.
 *
 * Each `createX` method opens a single `stacks.transaction(...)` and
 * writes the writ row and the companion doc inside one boundary. Parent
 * existence, parent-not-terminal, codex inheritance, and id generation
 * mirror Clerk's `post()` validation byte-for-byte. `transitionX`
 * methods update both `writ.phase` and the companion doc's `stage`
 * field atomically inside one transaction.
 */

import type { Plugin, StartupContext } from '@shardworks/nexus-core';
import { guild, generateId } from '@shardworks/nexus-core';
import type {
  Book,
  BookQuery,
  StacksApi,
  WhereClause,
} from '@shardworks/stacks-apparatus';
import type {
  ClerkApi,
  WritDoc,
  WritPhase,
  WritTypeConfig,
} from '@shardworks/clerk-apparatus';

import type {
  CartographApi,
  ChargeDoc,
  ChargeFilters,
  ChargeStage,
  CreateChargeRequest,
  CreatePieceRequest,
  CreateVisionRequest,
  PieceDoc,
  PieceFilters,
  PieceStage,
  TransitionChargeRequest,
  TransitionPieceRequest,
  TransitionVisionRequest,
  VisionDoc,
  VisionFilters,
  VisionStage,
} from './types.ts';

import {
  visionCreate,
  visionShow,
  visionList,
  visionPatch,
  visionTransition,
  visionApply,
  chargeCreate,
  chargeShow,
  chargeList,
  chargePatch,
  chargeTransition,
  pieceCreate,
  pieceShow,
  pieceList,
  piecePatch,
  pieceTransition,
} from './tools/index.ts';

// ── Writ-type configs ────────────────────────────────────────────────
//
// Six-state mandate-clone byte-shape, identical to astrolabe's
// `STEP_CONFIG` / `OBSERVATION_SET_CONFIG`. NO `childrenBehavior`
// cascade — the typed API and downstream consumers coordinate
// patron-walkthrough semantics; the registry stays generic.

const VISION_CONFIG: WritTypeConfig = {
  name: 'vision',
  states: [
    { name: 'new', classification: 'initial', allowedTransitions: ['open', 'cancelled'] },
    { name: 'open', classification: 'active', allowedTransitions: ['stuck', 'completed', 'failed', 'cancelled'] },
    { name: 'stuck', classification: 'active', attrs: ['stuck'], allowedTransitions: ['open', 'failed', 'cancelled'] },
    { name: 'completed', classification: 'terminal', attrs: ['success'], allowedTransitions: [] },
    { name: 'failed', classification: 'terminal', attrs: ['failure'], allowedTransitions: [] },
    { name: 'cancelled', classification: 'terminal', attrs: ['cancelled'], allowedTransitions: [] },
  ],
};

const CHARGE_CONFIG: WritTypeConfig = {
  name: 'charge',
  states: [
    { name: 'new', classification: 'initial', allowedTransitions: ['open', 'cancelled'] },
    { name: 'open', classification: 'active', allowedTransitions: ['stuck', 'completed', 'failed', 'cancelled'] },
    { name: 'stuck', classification: 'active', attrs: ['stuck'], allowedTransitions: ['open', 'failed', 'cancelled'] },
    { name: 'completed', classification: 'terminal', attrs: ['success'], allowedTransitions: [] },
    { name: 'failed', classification: 'terminal', attrs: ['failure'], allowedTransitions: [] },
    { name: 'cancelled', classification: 'terminal', attrs: ['cancelled'], allowedTransitions: [] },
  ],
};

const PIECE_CONFIG: WritTypeConfig = {
  name: 'piece',
  states: [
    { name: 'new', classification: 'initial', allowedTransitions: ['open', 'cancelled'] },
    { name: 'open', classification: 'active', allowedTransitions: ['stuck', 'completed', 'failed', 'cancelled'] },
    { name: 'stuck', classification: 'active', attrs: ['stuck'], allowedTransitions: ['open', 'failed', 'cancelled'] },
    { name: 'completed', classification: 'terminal', attrs: ['success'], allowedTransitions: [] },
    { name: 'failed', classification: 'terminal', attrs: ['failure'], allowedTransitions: [] },
    { name: 'cancelled', classification: 'terminal', attrs: ['cancelled'], allowedTransitions: [] },
  ],
};

/**
 * Initial stage that pairs with a writ's `new` initial phase. The
 * typed-API `createX` methods set this on the companion doc at creation
 * time so the doc's stage starts in lockstep with the writ's phase.
 */
const INITIAL_STAGE = 'draft' as const;

/**
 * Allowed initial (phase, stage) pairs for `createVision`. A vision
 * cannot be born retired, so terminal stages (`sunset`, `cancelled`)
 * are deliberately absent — to drive a vision to a terminal state,
 * create it then call `transitionVision`.
 *
 * The mapping mirrors the call-site logic the on-disk vision-apply tool
 * uses when deriving the writ phase from the patron's sidecar `stage`.
 */
const VISION_INITIAL_STAGE_TO_PHASE: Record<string, WritPhase> = {
  draft: 'new',
  active: 'open',
};

/**
 * Return true when the given writ is in a terminal state per its
 * registered type config. Replicates `clerk.isTerminal()` against the
 * locally-resolved config so the call site doesn't need to round-trip
 * through the Clerk API mid-transaction.
 */
function isTerminalPhase(
  writ: WritDoc,
  getConfig: (name: string) => WritTypeConfig | undefined,
): boolean {
  const config = getConfig(writ.type);
  if (!config) {
    throw new Error(
      `[cartograph] writ "${writ.id}" carries unregistered type "${writ.type}".`,
    );
  }
  const state = config.states.find((s) => s.name === writ.phase);
  if (!state) {
    throw new Error(
      `[cartograph] writ "${writ.id}" carries phase "${writ.phase}" not declared in type "${writ.type}".`,
    );
  }
  return state.classification === 'terminal';
}

// ── Factory ──────────────────────────────────────────────────────────

export function createCartograph(): Plugin {
  let stacks: StacksApi;
  let clerk: ClerkApi;
  let visionsBook: Book<VisionDoc>;
  let chargesBook: Book<ChargeDoc>;
  let piecesBook: Book<PieceDoc>;

  // ── Generic helpers ────────────────────────────────────────────────

  /**
   * Build a list-style query for one of the three companion books.
   * Mirrors astrolabe's `list` body; only the field name differs (`stage`
   * vs `status`).
   */
  function buildListQuery(filters?: {
    stage?: string;
    codex?: string;
    limit?: number;
    offset?: number;
  }): BookQuery {
    const conditions: WhereClause = [];
    if (filters?.stage !== undefined) conditions.push(['stage', '=', filters.stage]);
    if (filters?.codex !== undefined) conditions.push(['codex', '=', filters.codex]);
    const limit = filters?.limit ?? 20;
    const offset = filters?.offset;
    return {
      ...(conditions.length > 0 ? { where: conditions } : {}),
      orderBy: ['createdAt', 'desc'],
      limit,
      ...(offset !== undefined ? { offset } : {}),
    };
  }

  /**
   * Validate parent existence, not-terminal, and (optionally) the parent's
   * type. Returns the parent writ doc on success. The transactional
   * writs-book handle is passed in by the caller so all reads/writes
   * commit under a single boundary.
   */
  async function validateParent(
    txWritsBook: Book<WritDoc>,
    parentId: string,
    childId: string,
    options: { allowedParentTypes?: string[]; childTypeName: string },
  ): Promise<WritDoc> {
    const parent = await txWritsBook.get(parentId);
    if (!parent) {
      throw new Error(`Parent writ "${parentId}" not found.`);
    }
    if (parentId === childId) {
      throw new Error(`Cannot create a writ as its own parent.`);
    }
    if (isTerminalPhase(parent, (name) => clerk.getWritTypeConfig(name))) {
      throw new Error(
        `Cannot add children to writ "${parentId}": phase is "${parent.phase}" (terminal). Children can only be added to writs in non-terminal states.`,
      );
    }
    if (options.allowedParentTypes !== undefined) {
      if (!options.allowedParentTypes.includes(parent.type)) {
        const allowed = options.allowedParentTypes.map((t) => `"${t}"`).join(' or ');
        throw new Error(
          `[cartograph] cannot create ${options.childTypeName} under writ "${parentId}": parent type is "${parent.type}", expected ${allowed}.`,
        );
      }
    }
    return parent;
  }

  // ── API ────────────────────────────────────────────────────────────

  const api: CartographApi = {
    // ── Vision ────────────────────────────────────────────────────

    async createVision(request: CreateVisionRequest): Promise<VisionDoc> {
      // Runtime guard for the typed-API parent invariant: a vision has
      // no parent. The static `CreateVisionRequest` shape does not
      // include `parentId`, but a structurally-typed caller could still
      // pass one — reject explicitly so the rule is enforced at the
      // boundary.
      const maybeParentId = (request as { parentId?: unknown }).parentId;
      if (typeof maybeParentId === 'string' && maybeParentId.length > 0) {
        throw new Error(
          '[cartograph] createVision: a vision is a top-level writ and cannot have a parent — refusing to create a vision with parentId.',
        );
      }

      // Initial-state resolution. Defaults to (phase=new, stage=draft) so
      // existing callers are unaffected. A caller may supply either or
      // both; whatever they supply must agree with the fixed mapping in
      // VISION_INITIAL_STAGE_TO_PHASE. Terminal initial states
      // (sunset/cancelled) are rejected — a vision cannot be born retired.
      const requestedStage: VisionStage = request.stage ?? INITIAL_STAGE;
      const expectedPhase = VISION_INITIAL_STAGE_TO_PHASE[requestedStage];
      if (expectedPhase === undefined) {
        throw new Error(
          `[cartograph] createVision: stage "${requestedStage}" is not a valid initial stage. ` +
            `A vision cannot be born retired — allowed initial stages are "draft" and "active". ` +
            `To drive a vision to a terminal state, create it then call transitionVision.`,
        );
      }
      const requestedPhase: WritPhase = request.phase ?? expectedPhase;
      if (requestedPhase !== expectedPhase) {
        throw new Error(
          `[cartograph] createVision: phase "${requestedPhase}" does not pair with stage "${requestedStage}". ` +
            `Allowed initial pairs are (phase=new, stage=draft) and (phase=open, stage=active).`,
        );
      }
      // Validate phase against the registered VISION_CONFIG, mirroring
      // transitionVision's defensive check. Catches an unregistered or
      // typo'd phase value before we write the writ row.
      const visionConfig = clerk.getWritTypeConfig('vision');
      if (!visionConfig) {
        throw new Error(
          '[cartograph] createVision: writ type "vision" is not registered with the Clerk.',
        );
      }
      const requestedState = visionConfig.states.find((s) => s.name === requestedPhase);
      if (!requestedState) {
        throw new Error(
          `[cartograph] createVision: phase "${requestedPhase}" is not declared in writ type "vision".`,
        );
      }

      // The createX methods cannot delegate to clerk.post because Clerk's
      // `post` does not accept an external transaction context, and the
      // writ row + companion doc must commit under one boundary.
      // Replicating Clerk's validation logic here is the cost of being a
      // typed atomic surface.
      return stacks.transaction(async (tx) => {
        const txWritsBook = tx.book<WritDoc>('clerk', 'writs');
        const txVisionsBook = tx.book<VisionDoc>('cartograph', 'visions');

        const childId = generateId('w', 6);
        const now = new Date().toISOString();

        const writ: WritDoc = {
          id: childId,
          type: 'vision',
          phase: requestedPhase,
          title: request.title,
          body: request.body,
          ...(request.codex !== undefined ? { codex: request.codex } : {}),
          createdAt: now,
          updatedAt: now,
        };

        await txWritsBook.put(writ);

        const doc: VisionDoc = {
          id: childId,
          stage: requestedStage,
          ...(request.codex !== undefined ? { codex: request.codex } : {}),
          createdAt: now,
          updatedAt: now,
        };

        await txVisionsBook.put(doc);
        return doc;
      });
    },

    async showVision(id: string): Promise<VisionDoc> {
      const doc = await visionsBook.get(id);
      if (!doc) {
        throw new Error(`Vision "${id}" not found.`);
      }
      return doc;
    },

    async listVisions(filters?: VisionFilters): Promise<VisionDoc[]> {
      return visionsBook.find(buildListQuery(filters));
    },

    async patchVision(
      id: string,
      fields: Partial<Omit<VisionDoc, 'id'>>,
    ): Promise<VisionDoc> {
      return visionsBook.patch(id, fields);
    },

    async transitionVision(
      id: string,
      request: TransitionVisionRequest,
    ): Promise<VisionDoc> {
      // Lifecycle coupling lives on the typed API. The caller specifies
      // both target phase and target stage explicitly because a single
      // phase may map to multiple stages (e.g. failed → cancelled vs
      // failed → sunset).
      return stacks.transaction(async (tx) => {
        const txWritsBook = tx.book<WritDoc>('clerk', 'writs');
        const txVisionsBook = tx.book<VisionDoc>('cartograph', 'visions');

        const writ = await txWritsBook.get(id);
        if (!writ) {
          throw new Error(`Writ "${id}" not found.`);
        }

        const config = clerk.getWritTypeConfig(writ.type);
        if (!config) {
          throw new Error(
            `[cartograph] writ "${id}" carries unregistered type "${writ.type}".`,
          );
        }
        const currentState = config.states.find((s) => s.name === writ.phase);
        if (!currentState) {
          throw new Error(
            `[cartograph] writ "${id}" carries phase "${writ.phase}" not declared in type "${writ.type}".`,
          );
        }
        if (!currentState.allowedTransitions.includes(request.phase)) {
          const legal =
            currentState.allowedTransitions.length === 0
              ? 'none (terminal state)'
              : currentState.allowedTransitions.map((s) => `"${s}"`).join(', ');
          throw new Error(
            `Cannot transition writ "${id}" from "${writ.phase}" to "${request.phase}": legal transitions from "${writ.phase}" are ${legal}.`,
          );
        }
        const targetState = config.states.find((s) => s.name === request.phase);
        if (!targetState) {
          throw new Error(
            `[cartograph] writ type "${writ.type}" has no state "${request.phase}".`,
          );
        }
        const isTerminal = targetState.classification === 'terminal';

        const now = new Date().toISOString();
        const writPatch: Partial<Omit<WritDoc, 'id'>> = {
          phase: request.phase,
          updatedAt: now,
          ...(isTerminal ? { resolvedAt: now } : {}),
          ...(request.resolution !== undefined ? { resolution: request.resolution } : {}),
        };
        await txWritsBook.patch(id, writPatch);

        return txVisionsBook.patch(id, { stage: request.stage, updatedAt: now });
      });
    },

    // ── Charge ────────────────────────────────────────────────────

    async createCharge(request: CreateChargeRequest): Promise<ChargeDoc> {
      return stacks.transaction(async (tx) => {
        const txWritsBook = tx.book<WritDoc>('clerk', 'writs');
        const txChargesBook = tx.book<ChargeDoc>('cartograph', 'charges');

        const childId = generateId('w', 6);
        const now = new Date().toISOString();
        const initialPhase = 'new';

        if (!request.parentId) {
          throw new Error(
            '[cartograph] createCharge requires a parentId — a charge must be created under a vision.',
          );
        }

        const parent = await validateParent(txWritsBook, request.parentId, childId, {
          allowedParentTypes: ['vision'],
          childTypeName: 'charge',
        });

        const codex = request.codex ?? parent.codex;

        const writ: WritDoc = {
          id: childId,
          type: 'charge',
          phase: initialPhase,
          title: request.title,
          body: request.body,
          ...(codex !== undefined ? { codex } : {}),
          parentId: request.parentId,
          createdAt: now,
          updatedAt: now,
        };

        await txWritsBook.put(writ);

        const doc: ChargeDoc = {
          id: childId,
          stage: INITIAL_STAGE,
          ...(codex !== undefined ? { codex } : {}),
          createdAt: now,
          updatedAt: now,
        };

        await txChargesBook.put(doc);
        return doc;
      });
    },

    async showCharge(id: string): Promise<ChargeDoc> {
      const doc = await chargesBook.get(id);
      if (!doc) {
        throw new Error(`Charge "${id}" not found.`);
      }
      return doc;
    },

    async listCharges(filters?: ChargeFilters): Promise<ChargeDoc[]> {
      return chargesBook.find(buildListQuery(filters));
    },

    async patchCharge(
      id: string,
      fields: Partial<Omit<ChargeDoc, 'id'>>,
    ): Promise<ChargeDoc> {
      return chargesBook.patch(id, fields);
    },

    async transitionCharge(
      id: string,
      request: TransitionChargeRequest,
    ): Promise<ChargeDoc> {
      return stacks.transaction(async (tx) => {
        const txWritsBook = tx.book<WritDoc>('clerk', 'writs');
        const txChargesBook = tx.book<ChargeDoc>('cartograph', 'charges');

        const writ = await txWritsBook.get(id);
        if (!writ) {
          throw new Error(`Writ "${id}" not found.`);
        }

        const config = clerk.getWritTypeConfig(writ.type);
        if (!config) {
          throw new Error(
            `[cartograph] writ "${id}" carries unregistered type "${writ.type}".`,
          );
        }
        const currentState = config.states.find((s) => s.name === writ.phase);
        if (!currentState) {
          throw new Error(
            `[cartograph] writ "${id}" carries phase "${writ.phase}" not declared in type "${writ.type}".`,
          );
        }
        if (!currentState.allowedTransitions.includes(request.phase)) {
          const legal =
            currentState.allowedTransitions.length === 0
              ? 'none (terminal state)'
              : currentState.allowedTransitions.map((s) => `"${s}"`).join(', ');
          throw new Error(
            `Cannot transition writ "${id}" from "${writ.phase}" to "${request.phase}": legal transitions from "${writ.phase}" are ${legal}.`,
          );
        }
        const targetState = config.states.find((s) => s.name === request.phase);
        if (!targetState) {
          throw new Error(
            `[cartograph] writ type "${writ.type}" has no state "${request.phase}".`,
          );
        }
        const isTerminal = targetState.classification === 'terminal';

        const now = new Date().toISOString();
        const writPatch: Partial<Omit<WritDoc, 'id'>> = {
          phase: request.phase,
          updatedAt: now,
          ...(isTerminal ? { resolvedAt: now } : {}),
          ...(request.resolution !== undefined ? { resolution: request.resolution } : {}),
        };
        await txWritsBook.patch(id, writPatch);

        return txChargesBook.patch(id, { stage: request.stage, updatedAt: now });
      });
    },

    // ── Piece ─────────────────────────────────────────────────────

    async createPiece(request: CreatePieceRequest): Promise<PieceDoc> {
      return stacks.transaction(async (tx) => {
        const txWritsBook = tx.book<WritDoc>('clerk', 'writs');
        const txPiecesBook = tx.book<PieceDoc>('cartograph', 'pieces');

        const childId = generateId('w', 6);
        const now = new Date().toISOString();
        const initialPhase = 'new';

        if (!request.parentId) {
          throw new Error(
            '[cartograph] createPiece requires a parentId — a piece must be created under a charge or piece.',
          );
        }

        const parent = await validateParent(txWritsBook, request.parentId, childId, {
          allowedParentTypes: ['charge', 'piece'],
          childTypeName: 'piece',
        });

        const codex = request.codex ?? parent.codex;

        const writ: WritDoc = {
          id: childId,
          type: 'piece',
          phase: initialPhase,
          title: request.title,
          body: request.body,
          ...(codex !== undefined ? { codex } : {}),
          parentId: request.parentId,
          createdAt: now,
          updatedAt: now,
        };

        await txWritsBook.put(writ);

        const doc: PieceDoc = {
          id: childId,
          stage: INITIAL_STAGE,
          ...(codex !== undefined ? { codex } : {}),
          createdAt: now,
          updatedAt: now,
        };

        await txPiecesBook.put(doc);
        return doc;
      });
    },

    async showPiece(id: string): Promise<PieceDoc> {
      const doc = await piecesBook.get(id);
      if (!doc) {
        throw new Error(`Piece "${id}" not found.`);
      }
      return doc;
    },

    async listPieces(filters?: PieceFilters): Promise<PieceDoc[]> {
      return piecesBook.find(buildListQuery(filters));
    },

    async patchPiece(
      id: string,
      fields: Partial<Omit<PieceDoc, 'id'>>,
    ): Promise<PieceDoc> {
      return piecesBook.patch(id, fields);
    },

    async transitionPiece(
      id: string,
      request: TransitionPieceRequest,
    ): Promise<PieceDoc> {
      return stacks.transaction(async (tx) => {
        const txWritsBook = tx.book<WritDoc>('clerk', 'writs');
        const txPiecesBook = tx.book<PieceDoc>('cartograph', 'pieces');

        const writ = await txWritsBook.get(id);
        if (!writ) {
          throw new Error(`Writ "${id}" not found.`);
        }

        const config = clerk.getWritTypeConfig(writ.type);
        if (!config) {
          throw new Error(
            `[cartograph] writ "${id}" carries unregistered type "${writ.type}".`,
          );
        }
        const currentState = config.states.find((s) => s.name === writ.phase);
        if (!currentState) {
          throw new Error(
            `[cartograph] writ "${id}" carries phase "${writ.phase}" not declared in type "${writ.type}".`,
          );
        }
        if (!currentState.allowedTransitions.includes(request.phase)) {
          const legal =
            currentState.allowedTransitions.length === 0
              ? 'none (terminal state)'
              : currentState.allowedTransitions.map((s) => `"${s}"`).join(', ');
          throw new Error(
            `Cannot transition writ "${id}" from "${writ.phase}" to "${request.phase}": legal transitions from "${writ.phase}" are ${legal}.`,
          );
        }
        const targetState = config.states.find((s) => s.name === request.phase);
        if (!targetState) {
          throw new Error(
            `[cartograph] writ type "${writ.type}" has no state "${request.phase}".`,
          );
        }
        const isTerminal = targetState.classification === 'terminal';

        const now = new Date().toISOString();
        const writPatch: Partial<Omit<WritDoc, 'id'>> = {
          phase: request.phase,
          updatedAt: now,
          ...(isTerminal ? { resolvedAt: now } : {}),
          ...(request.resolution !== undefined ? { resolution: request.resolution } : {}),
        };
        await txWritsBook.patch(id, writPatch);

        return txPiecesBook.patch(id, { stage: request.stage, updatedAt: now });
      });
    },
  };

  // ── Apparatus ─────────────────────────────────────────────────────

  return {
    apparatus: {
      requires: ['stacks', 'clerk'],
      // Recommend `oculus` so the writs page renders the new types via
      // its type-vocabulary helper. Without oculus the data is invisible
      // to the dashboard; recommending it surfaces a clean startup
      // warning when an operator forgets.
      recommends: ['oculus'],

      supportKit: {
        books: {
          visions: { indexes: ['stage', 'codex', 'createdAt'] },
          charges: { indexes: ['stage', 'codex', 'createdAt'] },
          pieces: { indexes: ['stage', 'codex', 'createdAt'] },
        },

        // Cartograph contributes 16 patron-facing CLI tools — five per
        // (vision/charge/piece × create/show/list/patch/transition) plus
        // the on-disk authoring tool `vision-apply`. The framework
        // `nsg` auto-builder discovers them via The Instrumentarium and
        // groups them by hyphen prefix automatically (D2/D3 in the
        // commission spec).
        tools: [
          visionCreate,
          visionShow,
          visionList,
          visionPatch,
          visionTransition,
          visionApply,
          chargeCreate,
          chargeShow,
          chargeList,
          chargePatch,
          chargeTransition,
          pieceCreate,
          pieceShow,
          pieceList,
          piecePatch,
          pieceTransition,
        ],
      },

      provides: api,

      start(_ctx: StartupContext): void {
        const g = guild();
        stacks = g.apparatus<StacksApi>('stacks');
        clerk = g.apparatus<ClerkApi>('clerk');

        visionsBook = stacks.book<VisionDoc>('cartograph', 'visions');
        chargesBook = stacks.book<ChargeDoc>('cartograph', 'charges');
        piecesBook = stacks.book<PieceDoc>('cartograph', 'pieces');

        // Register the three writ types. Cartograph's `requires: ['stacks',
        // 'clerk']` declaration ensures Clerk has already started; the
        // registration window stays open until the framework's
        // `phase:started` signal seals it.
        clerk.registerWritType(VISION_CONFIG);
        clerk.registerWritType(CHARGE_CONFIG);
        clerk.registerWritType(PIECE_CONFIG);
      },
    },
  };
}

// Re-export the type-config constants so tests can assert them without
// reaching back into the apparatus module.
export { VISION_CONFIG, CHARGE_CONFIG, PIECE_CONFIG };

// Local type re-exports kept narrow — see ./index.ts for the full surface.
export type {
  ChargeStage,
  PieceStage,
  VisionStage,
  WritPhase,
};

/**
 * Cartograph — public types.
 *
 * The Cartograph contributes three writ types to the Clerk —
 * `vision`, `charge`, and `piece` — and shadows each one with a
 * typed companion document stored in its own book.
 *
 * Companion-doc convention follows astrolabe's `PlanDoc`: the doc id
 * matches the writ id one-for-one; both rows are written under one
 * `stacks.transaction(...)` boundary by `createX`. Vision text lives on
 * `writ.body`; the companion doc carries typed metadata only — the
 * minimal field set is deliberate (D14 in the commission spec).
 *
 * Stage enums are per-type so each carries the domain-level vocabulary
 * relevant to its level of the decomposition ladder (see D10 in the
 * commission spec).
 */

import type { WritPhase } from '@shardworks/clerk-apparatus';

// ── Stage enums (per type) ───────────────────────────────────────────

/**
 * Lifecycle stage on a `VisionDoc`. Captures the patron-facing meaning
 * of a vision's progression separately from the writ's `phase`:
 *
 *  - `draft`     — the vision is being shaped; not yet active.
 *  - `active`    — the vision is in flight.
 *  - `sunset`    — the patron retired the vision (graceful wind-down).
 *  - `cancelled` — the vision was cancelled before reaching `sunset`.
 *
 * The typed-API `transitionVision` helper is the only sanctioned path
 * that updates this field; it writes both `writ.phase` and `stage`
 * inside one transaction so the two never drift.
 */
export type VisionStage = 'draft' | 'active' | 'sunset' | 'cancelled';

/**
 * Lifecycle stage on a `ChargeDoc`. The `validated` value records the
 * patron-walkthrough acceptance moment that distinguishes a charge from
 * a piece:
 *
 *  - `draft`      — the charge is being shaped.
 *  - `active`     — the charge is in flight under its parent vision.
 *  - `validated`  — the patron walked through and accepted the charge.
 *  - `dropped`    — the charge was abandoned without acceptance.
 */
export type ChargeStage = 'draft' | 'active' | 'validated' | 'dropped';

/**
 * Lifecycle stage on a `PieceDoc`. Pieces are internal organization;
 * the `done` value records completion as a structural fact rather than
 * a patron-walkthrough fact:
 *
 *  - `draft`   — the piece is being shaped.
 *  - `active`  — the piece is in flight.
 *  - `done`    — the piece is complete.
 *  - `dropped` — the piece was abandoned.
 */
export type PieceStage = 'draft' | 'active' | 'done' | 'dropped';

// ── Companion documents ──────────────────────────────────────────────

/**
 * Companion document for a `vision` writ. Keyed by the writ id one-for-
 * one. Carries typed metadata only — vision text lives on `writ.body`.
 *
 * The `[key: string]: unknown` index signature satisfies Stacks'
 * `BookEntry` constraint and lets future commissions grow the field set
 * non-breakingly. The patch surface mirrors astrolabe's `PlanDoc.patch`.
 */
export interface VisionDoc {
  /** Index signature required to satisfy BookEntry. */
  [key: string]: unknown;
  /** The vision writ's id — primary key, matches the writ id. */
  id: string;
  /** Lifecycle stage. Coupled to `writ.phase` by the typed-API transition helpers. */
  stage: VisionStage;
  /** Codex this vision targets. Inherited from the writ at creation time. */
  codex?: string;
  /** ISO timestamp when the doc was created. */
  createdAt: string;
  /** ISO timestamp of the last mutation. */
  updatedAt: string;
}

/**
 * Companion document for a `charge` writ. Same shape rules as
 * `VisionDoc` — keyed by writ id, minimal fields, index signature for
 * forward compatibility.
 */
export interface ChargeDoc {
  /** Index signature required to satisfy BookEntry. */
  [key: string]: unknown;
  /** The charge writ's id — primary key, matches the writ id. */
  id: string;
  /** Lifecycle stage. Coupled to `writ.phase` by the typed-API transition helpers. */
  stage: ChargeStage;
  /** Codex this charge targets. Inherited from the writ at creation time. */
  codex?: string;
  /** ISO timestamp when the doc was created. */
  createdAt: string;
  /** ISO timestamp of the last mutation. */
  updatedAt: string;
}

/**
 * Companion document for a `piece` writ. Same shape rules as
 * `VisionDoc`/`ChargeDoc` — keyed by writ id, minimal fields, index
 * signature for forward compatibility.
 */
export interface PieceDoc {
  /** Index signature required to satisfy BookEntry. */
  [key: string]: unknown;
  /** The piece writ's id — primary key, matches the writ id. */
  id: string;
  /** Lifecycle stage. Coupled to `writ.phase` by the typed-API transition helpers. */
  stage: PieceStage;
  /** Codex this piece targets. Inherited from the writ at creation time. */
  codex?: string;
  /** ISO timestamp when the doc was created. */
  createdAt: string;
  /** ISO timestamp of the last mutation. */
  updatedAt: string;
}

// ── Filters ──────────────────────────────────────────────────────────

/**
 * Filters for listing visions. Mirrors astrolabe's `PlanFilters` shape
 * with `stage` replacing `status`. Lists are ordered by `createdAt desc`.
 */
export interface VisionFilters {
  /** Filter by stage. */
  stage?: VisionStage;
  /** Filter by codex. */
  codex?: string;
  /** Maximum number of results (default: 20). */
  limit?: number;
  /** Number of results to skip. */
  offset?: number;
}

/** Filters for listing charges. Mirrors `VisionFilters`. */
export interface ChargeFilters {
  /** Filter by stage. */
  stage?: ChargeStage;
  /** Filter by codex. */
  codex?: string;
  /** Maximum number of results (default: 20). */
  limit?: number;
  /** Number of results to skip. */
  offset?: number;
}

/** Filters for listing pieces. Mirrors `VisionFilters`. */
export interface PieceFilters {
  /** Filter by stage. */
  stage?: PieceStage;
  /** Filter by codex. */
  codex?: string;
  /** Maximum number of results (default: 20). */
  limit?: number;
  /** Number of results to skip. */
  offset?: number;
}

// ── Create requests ──────────────────────────────────────────────────

/**
 * Request to create a top-level vision. Visions have no parent — passing
 * a non-empty `parentId` is rejected by the typed API.
 *
 * The optional `phase` and `stage` fields let a caller (e.g.
 * `nsg vision apply`) bootstrap a vision directly into an active state
 * inside the same atomic transaction that creates the writ row and the
 * companion VisionDoc. The phase/stage pair must match the fixed mapping
 * the typed API maintains for initial creation:
 *
 *   - phase `'new'`  paired with stage `'draft'`  (default)
 *   - phase `'open'` paired with stage `'active'`
 *
 * Terminal initial states (`sunset` / `cancelled`) are rejected — a vision
 * cannot be born retired. To retire a vision, create it then call
 * `transitionVision`.
 */
export interface CreateVisionRequest {
  /** Short human-readable title describing the vision. */
  title: string;
  /** Long-form vision text, stored on `writ.body`. */
  body: string;
  /** Optional target codex. */
  codex?: string;
  /**
   * Optional initial phase on the underlying writ. Defaults to `'new'`.
   * Must be paired with a matching `stage` per the initial-state mapping.
   */
  phase?: WritPhase;
  /**
   * Optional initial stage on the companion VisionDoc. Defaults to
   * `'draft'`. Must pair with `phase` per the initial-state mapping.
   * Terminal stages (`sunset`, `cancelled`) are rejected.
   */
  stage?: VisionStage;
}

/**
 * Request to create a charge under a vision. The typed API rejects when
 * `parentId` is missing or when the parent's writ type is not `vision`.
 */
export interface CreateChargeRequest {
  /** Required: must reference an existing vision in a non-terminal state. */
  parentId: string;
  /** Short human-readable title describing the charge. */
  title: string;
  /** Detail text, stored on `writ.body`. */
  body: string;
  /** Optional target codex. Defaults to the parent vision's codex. */
  codex?: string;
}

/**
 * Request to create a piece under a charge or piece. The typed API
 * rejects when `parentId` is missing or when the parent's writ type is
 * not `charge` or `piece`.
 */
export interface CreatePieceRequest {
  /** Required: must reference an existing charge or piece in a non-terminal state. */
  parentId: string;
  /** Short human-readable title describing the piece. */
  title: string;
  /** Detail text, stored on `writ.body`. */
  body: string;
  /** Optional target codex. Defaults to the parent's codex. */
  codex?: string;
}

// ── Transition requests ──────────────────────────────────────────────

/**
 * Lifecycle-coupled transition request for a vision. The caller supplies
 * both the target `phase` and the target `stage` because the mapping is
 * not always one-to-one — for example, a vision driven to `failed` might
 * mean stage `cancelled` or stage `sunset` depending on context. The
 * typed API writes both fields atomically.
 */
export interface TransitionVisionRequest {
  /** Target phase on the underlying writ. */
  phase: WritPhase;
  /** Target stage on the companion VisionDoc. */
  stage: VisionStage;
  /** Optional resolution string. Set on terminal transitions. */
  resolution?: string;
}

/**
 * Lifecycle-coupled transition request for a charge. See
 * `TransitionVisionRequest` for why both `phase` and `stage` are
 * specified explicitly.
 */
export interface TransitionChargeRequest {
  /** Target phase on the underlying writ. */
  phase: WritPhase;
  /** Target stage on the companion ChargeDoc. */
  stage: ChargeStage;
  /** Optional resolution string. Set on terminal transitions. */
  resolution?: string;
}

/**
 * Lifecycle-coupled transition request for a piece. See
 * `TransitionVisionRequest` for why both `phase` and `stage` are
 * specified explicitly.
 */
export interface TransitionPieceRequest {
  /** Target phase on the underlying writ. */
  phase: WritPhase;
  /** Target stage on the companion PieceDoc. */
  stage: PieceStage;
  /** Optional resolution string. Set on terminal transitions. */
  resolution?: string;
}

// ── API ──────────────────────────────────────────────────────────────

/**
 * The `provides` interface for the Cartograph apparatus.
 *
 * The typed-API surface is the **only** layer that enforces the ladder's
 * parent invariants:
 *
 *   - `createVision` rejects any non-empty `parentId`.
 *   - `createCharge` rejects unless the parent's writ type is `vision`.
 *   - `createPiece`  rejects unless the parent's writ type is `charge` or `piece`.
 *
 * Raw `clerk.post({ type: 'vision' })` continues to succeed without
 * parent-type checks — the typed API is the validator. WritTypeConfig
 * deliberately carries no parentTypes/allowedChildren restrictions.
 *
 * Each `createX` opens a single Stacks transaction and writes both the
 * writ row and the companion document inside one boundary. Parent
 * existence, parent-not-terminal, codex inheritance, and id generation
 * mirror Clerk's `post()` validation byte-for-byte (the duplication is
 * the cost of being a typed atomic surface).
 *
 * Each `transitionX` writes both `writ.phase` and the companion doc's
 * `stage` field atomically. The caller specifies both targets
 * explicitly because a single phase may map to multiple stages
 * depending on context.
 */
export interface CartographApi {
  // ── Vision ──────────────────────────────────────────────────────

  /** Create a top-level vision. Rejects when `parentId` is set. */
  createVision(request: CreateVisionRequest): Promise<VisionDoc>;
  /** Show a vision by writ id. Throws if the doc is not found. */
  showVision(id: string): Promise<VisionDoc>;
  /** List visions, ordered by createdAt descending. */
  listVisions(filters?: VisionFilters): Promise<VisionDoc[]>;
  /** Patch a vision's companion doc. Returns the updated document. */
  patchVision(id: string, fields: Partial<Omit<VisionDoc, 'id'>>): Promise<VisionDoc>;
  /** Atomically transition both the writ phase and the companion stage. */
  transitionVision(id: string, request: TransitionVisionRequest): Promise<VisionDoc>;

  // ── Charge ──────────────────────────────────────────────────────

  /** Create a charge under a vision. Rejects when the parent is not a vision. */
  createCharge(request: CreateChargeRequest): Promise<ChargeDoc>;
  /** Show a charge by writ id. Throws if the doc is not found. */
  showCharge(id: string): Promise<ChargeDoc>;
  /** List charges, ordered by createdAt descending. */
  listCharges(filters?: ChargeFilters): Promise<ChargeDoc[]>;
  /** Patch a charge's companion doc. Returns the updated document. */
  patchCharge(id: string, fields: Partial<Omit<ChargeDoc, 'id'>>): Promise<ChargeDoc>;
  /** Atomically transition both the writ phase and the companion stage. */
  transitionCharge(id: string, request: TransitionChargeRequest): Promise<ChargeDoc>;

  // ── Piece ───────────────────────────────────────────────────────

  /** Create a piece under a charge or piece. Rejects on any other parent type. */
  createPiece(request: CreatePieceRequest): Promise<PieceDoc>;
  /** Show a piece by writ id. Throws if the doc is not found. */
  showPiece(id: string): Promise<PieceDoc>;
  /** List pieces, ordered by createdAt descending. */
  listPieces(filters?: PieceFilters): Promise<PieceDoc[]>;
  /** Patch a piece's companion doc. Returns the updated document. */
  patchPiece(id: string, fields: Partial<Omit<PieceDoc, 'id'>>): Promise<PieceDoc>;
  /** Atomically transition both the writ phase and the companion stage. */
  transitionPiece(id: string, request: TransitionPieceRequest): Promise<PieceDoc>;
}

/**
 * @shardworks/cartograph-apparatus — The Cartograph.
 *
 * Decomposition-ladder data substrate: contributes the `vision`, `charge`,
 * and `piece` writ types to the Clerk and exposes a typed API that
 * enforces the ladder's parent invariants.
 *
 * See: README.md
 */

// ── Cartograph public types ────────────────────────────────────────────

export type {
  // Companion documents
  VisionDoc,
  ChargeDoc,
  PieceDoc,

  // Stage enums
  VisionStage,
  ChargeStage,
  PieceStage,

  // Filters
  VisionFilters,
  ChargeFilters,
  PieceFilters,

  // Create requests
  CreateVisionRequest,
  CreateChargeRequest,
  CreatePieceRequest,

  // Transition requests
  TransitionVisionRequest,
  TransitionChargeRequest,
  TransitionPieceRequest,

  // API surface
  CartographApi,
} from './types.ts';

export { createCartograph } from './cartograph.ts';

// ── Default export: the apparatus plugin ──────────────────────────────

import { createCartograph } from './cartograph.ts';
export default createCartograph();

/**
 * Clerk public types.
 *
 * All types exported from @shardworks/clerk-apparatus.
 */

import type {
  WritTypeConfig,
  WritTypeStateAttr,
  WritTypeStateClassification,
} from './writ-type-config.ts';

// ── Writ phase ───────────────────────────────────────────────────────

/**
 * The mandate writ type's lifecycle states.
 *
 * This union is mandate-specific — it enumerates the six states the built-in
 * mandate `WritTypeConfig` declares and is preserved for callers that
 * knowingly work exclusively with mandate writs. The structural type of
 * `WritDoc.phase` is `string` so any plugin-registered writ type's state
 * name can round-trip through the book; callers that need a mandate-phase
 * typed value should downcast explicitly.
 *
 * Mandate transitions:
 *   new    → open       (publish)   — draft enters the queue
 *   new    → cancelled  (cancel)
 *   open   → completed  (complete)
 *   open   → failed     (fail)
 *   open   → cancelled  (cancel)
 *   open   → stuck      (engine failure cascade)
 *   stuck  → open       (recovery/retry resumes execution)
 *   stuck  → failed     (obligation abandoned)
 *   stuck  → cancelled  (obligation withdrawn)
 *
 * completed, failed, cancelled are terminal — no further transitions.
 * stuck is non-terminal — it represents a "needs attention" state.
 */
export type WritPhase = 'new' | 'open' | 'stuck' | 'completed' | 'failed' | 'cancelled';

// ── Documents ────────────────────────────────────────────────────────

// ── status['clerk'] sub-slot ─────────────────────────────────────────

/**
 * The Clerk-owned sub-slot of `WritDoc.status`.
 *
 * Written by the children-behavior cascade engine at the moment a parent's
 * terminal transition fires: the engine records the *immediate* triggering
 * child's id so downstream observers (notably the Reckoner) can chase the
 * cascade chain back to the leaf cause without parsing the parent's
 * resolution string.
 *
 * Ownership: Clerk writes; downstream consumers read. Plugin convention is
 * the same as for any `status[<pluginId>]` sub-slot — see
 * `setWritStatus()` and the spec/status convention notes on `ClerkApi`.
 *
 * The slot is forward-only: there is no migration or backfill for writs
 * that already terminal'd before this slot existed. Pre-existing terminal
 * writs do not re-emit pulses, so the absence of a slot on a historical
 * writ is harmless.
 */
export interface ClerkWritStatus {
  /**
   * Id of the immediate child whose terminal transition fired the
   * children-behavior cascade onto this writ. Absent on writs that
   * reached terminal through a direct transition (no cascade).
   *
   * For multi-level cascades (root → mid → leaf), each level's parent
   * carries its own immediate triggering child id; consumers walk the
   * chain by reading each successive writ's `status['clerk']
   * .triggeringChildId`.
   */
  triggeringChildId?: string;
}

/**
 * Plugin id stamped on the Clerk's own observation sub-slot
 * (`status['clerk']`). Held as a constant so the engine and the
 * `setWritStatus` consumer agree on the key.
 */
export const CLERK_PLUGIN_ID = 'clerk';

/**
 * A writ document as stored in The Stacks.
 */
export interface WritDoc {
  /** Index signature required to satisfy BookEntry constraint. */
  [key: string]: unknown;
  /** Unique writ id (`w-{base36_timestamp}-{hex_random}`). Sortable by creation time. */
  id: string;
  /** Writ type — must be a type declared in guild config, or a built-in type. */
  type: string;
  /**
   * Current lifecycle state name (Clerk-owned; spec side of the spec/status
   * split). Structurally typed as `string` so any plugin-registered writ
   * type's state name can round-trip through the book. For mandate-typed
   * writs the value is constrained to a `WritPhase` literal at runtime, but
   * callers that need a narrower static type should downcast explicitly.
   */
  phase: string;
  /**
   * Plugin-owned observation slot (status side of the spec/status split).
   *
   * The observation slot is a plugin-keyed map (`Record<PluginId,
   * unknown>`): each top-level key is a plugin id, and the value is an
   * arbitrary shape that plugin publishes for post-hoc observation.
   * Ownership is convention-only — plugin `X` writes only to `status[X]`.
   *
   * There is exactly one sanctioned slot-write path:
   * `ClerkApi.setWritStatus(writId, pluginId, value)`, which performs a
   * transactional read-modify-write on the sub-slot keyed by `pluginId`
   * so sibling sub-slots are preserved under concurrent writers.
   * `transition()` silently strips `status` from its body, and the
   * generic `put()` / `patch()` paths on the writs book are not
   * supported slot-write mechanisms — every route other than
   * `setWritStatus()` would wholesale-replace the slot and clobber
   * sibling sub-slots. Readers access `writ.status?.[pluginId]` directly.
   *
   * The slot survives terminal phase transitions.
   */
  status?: Record<string, unknown>;
  /**
   * Plugin-owned metadata slot — sibling to `status` but reserved for
   * metadata-shape data (provenance, cross-references, classification
   * tags, configuration extensions) attached at writ creation or
   * registration time, rather than the post-hoc observation that
   * `status` records.
   *
   * The semantic distinction matters: `status` is for what a plugin
   * has *observed* about a writ after the fact (a stuck cause, a
   * triggering child, a gate result); `ext` is for what a plugin needs
   * the writ to *carry* as an attribute of its identity (a petition id,
   * a classifier tag, a foreign-system reference). Picking the wrong
   * slot layers metadata under an observation contract or vice versa,
   * so plugin authors should choose consciously.
   *
   * Structurally identical to `status`: a plugin-keyed map
   * (`Record<PluginId, unknown>`) where each top-level key is a plugin
   * id and the value is an arbitrary opaque shape. Ownership is
   * convention-only — plugin `X` writes only to `ext[X]`.
   *
   * There is exactly one sanctioned slot-write path:
   * `ClerkApi.setWritExt(writId, pluginId, value)`, which performs a
   * transactional read-modify-write on the sub-slot keyed by `pluginId`
   * so sibling sub-slots are preserved under concurrent writers.
   * `transition()` silently strips `ext` from its body, and the
   * generic `put()` / `patch()` paths on the writs book are not
   * supported slot-write mechanisms — every route other than
   * `setWritExt()` would wholesale-replace the slot and clobber
   * sibling sub-slots. Readers access `writ.ext?.[pluginId]` directly.
   *
   * Optional and absent by default — a freshly-posted writ reads
   * `ext === undefined` until a plugin writes its first sub-slot. The
   * slot survives terminal phase transitions.
   */
  ext?: Record<string, unknown>;
  /** Short human-readable title. */
  title: string;
  /** Detail text. */
  body: string;
  /** Target codex name. */
  codex?: string;
  /** Parent writ id. Absent on root writs. Immutable after creation. */
  parentId?: string;
  /** ISO timestamp when the writ was created. */
  createdAt: string;
  /** ISO timestamp of the last mutation. */
  updatedAt: string;
  /** ISO timestamp when the writ reached a terminal state. */
  resolvedAt?: string;
  /** Summary of how the writ resolved (set on any terminal transition). */
  resolution?: string;
}

// ── Requests ─────────────────────────────────────────────────────────

/**
 * Request to post a new commission (create a writ).
 */
/**
 * Request to edit a writ. Title and body can be edited in any status.
 * Type and codex can only be changed while the writ is in 'new' status.
 * All fields are optional — only provided fields are updated.
 */
export interface EditWritRequest {
  /** Writ id. */
  id: string;
  /** New title. */
  title?: string;
  /** New body text. */
  body?: string;
  /** New writ type. Must be a valid declared type. */
  type?: string;
  /** New target codex name. Pass empty string to clear. */
  codex?: string;
}

export interface PostCommissionRequest {
  /**
   * Writ type. Defaults to the guild's configured defaultType, or "mandate"
   * if no default is configured. Must be a registered writ type.
   */
  type?: string;
  /** Short human-readable title describing the work. */
  title: string;
  /** Detail text. */
  body: string;
  /** Optional target codex name. */
  codex?: string;
  /**
   * Create this writ as a child of the specified parent writ.
   * The parent must not be in a terminal state.
   */
  parentId?: string;
}

// ── Filters ──────────────────────────────────────────────────────────

/**
 * Filters for listing writs.
 */
export interface WritFilters {
  /**
   * Filter by phase. Accepts a single phase or an array of phases (OR).
   *
   * `phase` is mandate-scoped at the WHERE-clause level: when `phase` is
   * supplied without `type`, the implementation implicitly adds
   * `type = 'mandate'` so a non-mandate writ that happens to declare an
   * `open` state cannot match a `phase: 'open'` filter unscoped to its
   * type. To query a non-mandate type's same-named state, pass both
   * `type` and `phase` together (D7).
   */
  phase?: WritPhase | WritPhase[];
  /** Filter by writ type. Accepts a single type or an array of types (OR). */
  type?: string | string[];
  /**
   * Filter by state classification. Accepts a single classification or an
   * array (OR). Type-agnostic: applies across every registered writ type.
   * The closed three-value enum mirrors `WritTypeStateClassification`.
   */
  classification?:
    | WritTypeStateClassification
    | WritTypeStateClassification[];
  /** Filter to children of this parent writ. */
  parentId?: string;
  /** Maximum number of results (default: 20). */
  limit?: number;
  /** Number of results to skip. */
  offset?: number;
}

// ── Presentation projections ─────────────────────────────────────────

/**
 * Classification value as embedded on writ-bearing tool responses.
 *
 * Domain-side classifier helpers (`ClerkApi.isInitial`/`isActive`/
 * `isTerminal`) throw on an unregistered type or undeclared state — the
 * classifier preserves its fail-loud contract. The presentation projection
 * is tolerant and surfaces `'unknown'` for the same conditions so a single
 * legacy row cannot crash a list/tree/show response.
 */
export type WritPresentationClassification = 'initial' | 'active' | 'terminal' | 'unknown';

/**
 * Per-row presentation projection. `writ-list` returns rows of this
 * shape; `writ-tree`'s `WritTree.writ` and `writ-show`'s top-level writ
 * extend `WritDoc` with the same two derived fields.
 */
export interface WritWithPresentation extends WritDoc {
  /**
   * Classification of the writ's current state in its type config.
   * `'unknown'` indicates the writ's type is unregistered or its phase
   * is not declared in the registered config (presentation tolerance).
   */
  classification: WritPresentationClassification;
  /**
   * Outbound transition names declared on the writ's current state in
   * its type config. Empty for terminal states and for unknown
   * classifications.
   */
  allowedTransitions: string[];
}

/**
 * Compact parent/child reference shape used on `writ-show`'s `parent`
 * field and `children.items` entries. Carries the same `classification`
 * and `allowedTransitions` derivations as a full row so a renderer can
 * pick badge classes and action affordances uniformly.
 */
export interface WritReferenceWithPresentation {
  /** Writ id. */
  id: string;
  /** Writ title. */
  title: string;
  /** Writ type. */
  type: string;
  /** Current lifecycle state name. */
  phase: string;
  /** Classification of the writ's current state in its type config. */
  classification: WritPresentationClassification;
  /** Outbound transitions from the writ's current state. */
  allowedTransitions: string[];
}

// ── Tree shapes ──────────────────────────────────────────────────────

/**
 * A nested writ-and-children tree node, returned by `ClerkApi.tree()`.
 *
 * The shape is the writ document plus a recursively-typed `children` array
 * of further `WritTree` nodes. Mirrors ratchet's `ClickTree` so the same
 * mental model and rendering idioms apply across apparatus.
 *
 * Each node's `writ` carries the standard `WritDoc` fields plus the
 * presentation projection (`classification`, `allowedTransitions`) so
 * tree renderers can pick glyphs and action affordances per node without
 * reaching back into the type-config registry.
 */
export interface WritTree {
  /** The writ document at this node, with embedded presentation fields. */
  writ: WritWithPresentation;
  /** Direct children, each shaped as a `WritTree`. */
  children: WritTree[];
}

/**
 * Parameters for `ClerkApi.tree()`.
 *
 * - `rootId` switches between forest mode (omit) and subtree mode
 *   (single root). In subtree mode the returned array always has at most
 *   one element.
 * - `phase` and `type` apply prune semantics: any node failing the filter
 *   is dropped along with its entire subtree.
 * - `depth` caps recursion. The node at depth = `depth` is included but its
 *   children are not. `depth: 0` returns roots only.
 * - `rootLimit` and `rootOffset` page across the *root* layer of forest
 *   mode (preserves the page's `Load more` UX). They are ignored when
 *   `rootId` is supplied.
 *
 * In forest mode roots are returned in `createdAt desc` order (newest
 * first) to match `list()` and the existing writs-page UX. Children
 * within each subtree stay in `createdAt asc` order (oldest first) so the
 * visual shape of the tree is stable across sort/filter changes.
 */
export interface WritTreeParams {
  /** Restrict to the subtree rooted at this writ id. */
  rootId?: string;
  /**
   * Filter by writ phase (single or OR-list); prunes non-matching
   * subtrees. Mandate-scoped at the same level as `WritFilters.phase` —
   * see that field's docstring (D7).
   */
  phase?: WritPhase | WritPhase[];
  /** Filter by writ type (single or OR-list); prunes non-matching subtrees. */
  type?: string | string[];
  /**
   * Filter by state classification (single or OR-list); prunes
   * non-matching subtrees. Type-agnostic — applies across every
   * registered writ type.
   */
  classification?:
    | WritTypeStateClassification
    | WritTypeStateClassification[];
  /** Maximum recursion depth (0 = roots only). Node at the cap is included. */
  depth?: number;
  /** Root-slice limit for forest mode (default: unbounded). */
  rootLimit?: number;
  /** Root-slice offset for forest mode (default: 0). */
  rootOffset?: number;
}

// ── Configuration ───────────────────────────────────────────────

/**
 * Clerk apparatus configuration — lives under the `clerk` key in guild.json.
 *
 * Writ types are now contributed exclusively via
 * `ClerkApi.registerWritType` from a plugin's own `start()`. There is no
 * guild-config `writTypes` field; the operator's only handle on the writ-
 * type registry from guild config is the `defaultType` selection (which is
 * validated against the registry once startup seals).
 */
export interface ClerkConfig {
  /** Default writ type when commission-post is called without a type (default: "mandate"). Validated against the writ-type registry at startup; an unregistered name fails fast. */
  defaultType?: string;
}

// Augment GuildConfig so `guild().guildConfig().clerk` is typed without
// requiring a manual type parameter at the call site.
declare module '@shardworks/nexus-core' {
  interface GuildConfig {
    clerk?: ClerkConfig;
  }
}

// ── Link documents ───────────────────────────────────────────────────

/**
 * A link document as stored in The Stacks (clerk/links book).
 *
 * A writ link has two complementary identifiers for its relationship:
 *
 *   - `label` is a casual, human-facing string. It is open-ended, normalized
 *     at write time via the link-label normalization pipeline (lowercase,
 *     trim, camelCase split, snake_case/kebab-case split, whitespace
 *     collapse). Variant spellings of the same label collapse to a single
 *     canonical form; distinct labels remain distinct. Normalization is
 *     purely syntactic — it is NOT synonymy. `requires` and `depends on`
 *     normalize to different strings; callers that want to treat them as the
 *     same relationship should attach the same `kind` to both.
 *
 *   - `kind` is the load-bearing identifier. It is a stable, plugin-owned id
 *     drawn from the kit-contributed link-kind registry, and identifies the
 *     specific relationship a downstream consumer wants to react to
 *     (rendering parent/child, gating publish on `refines`, etc.). `null`
 *     when the caller treated this link as a casual label.
 */
export interface WritLinkDoc {
  /** Index signature required to satisfy BookEntry constraint. */
  [key: string]: unknown;
  /** Deterministic composite key: `{sourceId}:{targetId}:{normalized label}`. */
  id: string;
  /** The writ that is the origin of this relationship. */
  sourceId: string;
  /** The writ that is the target of this relationship. */
  targetId: string;
  /**
   * Casual relationship label — an open string normalized syntactically at
   * write time (e.g. "fixes", "retries", "supersedes", "duplicates",
   * "depends on"). NOT a synonymy layer. For load-bearing identity, use
   * `kind`.
   */
  label: string;
  /**
   * Load-bearing identifier for this relationship. When non-null, references
   * a registered kind id from the `linkKinds` kit registry and is the field
   * downstream consumers key on. Always present on each row (`null` when
   * the caller did not attach a kind).
   */
  kind: string | null;
  /** ISO timestamp when the link was created. */
  createdAt: string;
}

// ── Link kind registry ───────────────────────────────────────────────

/**
 * A link-kind contribution declared by a kit's `linkKinds` array.
 *
 * Kit authors use this shape when populating `ClerkKit.linkKinds`. Kind ids
 * must be prefixed with the contributing plugin's id followed by `.` and a
 * kebab-case suffix — e.g. kit `astrolabe` contributing `astrolabe.refines`.
 * The registry-projection view (returned by `listKinds()`) is `LinkKindDoc`,
 * which embeds the resolved owner plugin id; kit authors do not repeat their
 * plugin id on each entry.
 */
export interface KindEntry {
  /**
   * Fully-qualified kind id. Must begin with `{pluginId}.` and be followed
   * by a non-empty kebab-case suffix (lowercase letters, digits, and hyphens,
   * not starting or ending with a hyphen).
   *
   * Carve-out: contributions from the Clerk plugin itself (where the
   * contributing plugin id equals the Clerk's own id) may additionally use
   * a bare kebab id without a `{pluginId}.` prefix — e.g. `depends-on`.
   * The Clerk owns the writ link substrate and therefore owns the
   * unprefixed namespace within that substrate. The carve-out is exclusive
   * to Clerk; every other plugin must continue to use the prefixed form.
   */
  id: string;
  /** Human-readable description of the relationship this kind denotes. */
  description: string;
}

/**
 * A link-kind record as projected by `listKinds()`.
 *
 * Unlike `KindEntry`, this shape embeds the resolved owner plugin id so
 * consumers of the registry do not need to parse it back out of `id`.
 */
export interface LinkKindDoc {
  /** Fully-qualified kind id. */
  id: string;
  /** Plugin id of the kit that contributed this kind. */
  ownerPlugin: string;
  /** Human-readable description of this kind. */
  description: string;
}

/**
 * Result of querying links for a writ — both directions in one response.
 */
export interface WritLinks {
  /** Links where this writ is the source (this writ → other writ). */
  outbound: WritLinkDoc[];
  /** Links where this writ is the target (other writ → this writ). */
  inbound: WritLinkDoc[];
}

// ── Writ type metadata ──────────────────────────────────────────────

/**
 * Per-state metadata projected from a `WritTypeStateDefinition` for the
 * `/api/writ/types` and `nsg writ types` surfaces. Carries everything a
 * presentation layer needs to derive vocabulary, badges, and action
 * affordances without consulting the type-config registry per row.
 */
export interface WritTypeStateInfo {
  /** State name. */
  name: string;
  /** State's role in the lifecycle. */
  classification: WritTypeStateClassification;
  /** Per-state attribute tags (e.g. `success`, `failure`, `cancelled`). */
  attrs: WritTypeStateAttr[];
  /** Outbound transitions declared on this state. */
  allowedTransitions: string[];
}

/**
 * Metadata for a registered writ type, returned by listWritTypes().
 */
export interface WritTypeInfo {
  /** The writ type name. */
  name: string;
  /**
   * Reserved for a future config-carried description field. Always `null`
   * today — `WritTypeConfig` does not currently model a description, and
   * the legacy guild-config / kit-channel description fields are gone.
   */
  description: string | null;
  /**
   * Origin of this type. `"builtin"` is reserved for `mandate`, which the
   * Clerk plugin registers from its own `start()`; every other registered
   * type carries `"plugin"`. The Clerk does not track the calling plugin's
   * id — there is no implicit hand-off of caller identity into
   * `registerWritType`.
   */
  source: 'builtin' | 'plugin';
  /** Whether this is the guild's default writ type. */
  isDefault: boolean;
  /**
   * The full state catalogue for this type — one entry per state declared
   * in the type's registered `WritTypeConfig`, in the order it was
   * declared. Each entry projects the state's name, classification, attrs,
   * and outbound transitions so a presentation layer can derive vocabulary
   * (badges, indicators, action labels) without a separate registry
   * lookup.
   */
  states: WritTypeStateInfo[];
}

// ── API ──────────────────────────────────────────────────────────────

/**
 * The Clerk's runtime API — retrieved via guild().apparatus<ClerkApi>('clerk').
 */
export interface ClerkApi {
  /**
   * Post a new commission, creating a writ in its registered type's
   * declared `initial` state. The writ type must be registered with
   * `registerWritType`; an unknown type is rejected. The caller decides
   * whether to advance the writ further (e.g. `commission-post` auto-
   * publishes mandate writs to `open` by default — see that tool); the
   * `post()` API itself is type-agnostic and never auto-advances.
   */
  post(request: PostCommissionRequest): Promise<WritDoc>;

  /**
   * Show a writ by id. Throws if not found.
   */
  show(id: string): Promise<WritDoc>;

  /**
   * Resolve a writ id prefix to the full id. Mirrors ratchet's resolveId
   * for clicks — callers may pass the short display form (e.g. `w-mo2xi6pt`)
   * and receive the full id back. Throws when no writ matches or when the
   * prefix is ambiguous.
   */
  resolveId(prefix: string): Promise<string>;

  /**
   * List writs with optional filters, ordered by createdAt descending.
   */
  list(filters?: WritFilters): Promise<WritDoc[]>;

  /**
   * Count writs matching optional filters.
   */
  count(filters?: WritFilters): Promise<number>;

  /**
   * Count writs currently in any `active`-classified state across every
   * registered writ type.
   *
   * Walks the writ-type registry on each call (no caching) and composes a
   * per-type OR-form query of the shape `[type, phase IN [active-states-of-type]]`.
   * Returns `0` when the registry is empty, when no registered type
   * declares any `active` state, or when no rows match.
   *
   * This is the classification-driven primitive behind the Reckoner's
   * drain detector and any future apparatus that needs a multi-type
   * "is anything in flight?" count. Existing per-phase counts (e.g.
   * `count({ phase: 'open' })`) remain available for type-specific reads.
   */
  countActive(): Promise<number>;

  /**
   * Walk the writ hierarchy and return a forest (or a single subtree when
   * `rootId` is provided). Mirrors ratchet's `tree()` precedent.
   *
   * Filters apply with prune semantics: a node failing `phase` or `type`
   * is excluded together with its entire subtree. The `depth` cap halts
   * recursion below — the node at the cap is still included, but no
   * descendants of it are walked. `rootLimit` / `rootOffset` page across
   * the root layer of forest mode and are ignored when `rootId` is given.
   */
  tree(params?: WritTreeParams): Promise<WritTree[]>;

  /**
   * Count all descendants of a writ grouped by phase.
   *
   * Walks the parent/child tree recursively beneath `writId`, tallying each
   * descendant's phase. The root writ (the writ identified by `writId`) is
   * excluded from the count — only its descendants contribute. The result is
   * a plain object keyed by `WritPhase` with numeric values; phases with no
   * matching descendants are simply absent.
   *
   * This is the traversal primitive behind `writ-show`'s `children.summary`
   * field, and is also reusable by any future subtree-oriented tooling (e.g.
   * a `writ-tree` apparatus). Throws if the writ does not exist.
   */
  countDescendantsByPhase(writId: string): Promise<Record<WritPhase, number>>;

  /**
   * Transition a writ to a new phase, optionally setting additional fields.
   * Validates that the transition is legal.
   *
   * Managed fields supplied in `fields` are silently dropped before the
   * patch is applied: `id`, `phase`, `status`, `createdAt`, `updatedAt`,
   * `resolvedAt`, and `parentId`. `phase` is managed by the state machine;
   * the plugin-owned observation slot `status` is writable only via
   * `setWritStatus()` (the one sanctioned slot-write path) so that
   * sibling sub-slots are preserved under concurrent writers. The generic
   * `put()` / `patch()` paths are not supported slot-write mechanisms.
   */
  transition(id: string, to: WritPhase, fields?: Partial<WritDoc>): Promise<WritDoc>;

  /**
   * Write a plugin-owned sub-slot of the writ's observation `status` map.
   *
   * The slot is the "status" side of the spec/status split: plugins publish
   * post-hoc observations here (stuck causes, gate state, provenance, …)
   * without polluting the Clerk-owned `phase` state machine.
   *
   * The call is a transactional read-modify-write — the sub-slot keyed by
   * `pluginId` is replaced with `value`, but sibling sub-slots owned by
   * other plugins are preserved. Writes emit CDC update events like any
   * other field change, and survive terminal phase transitions.
   *
   * Ownership is convention-only: plugin `X` writes only `status[X]`.
   * There is no runtime guard.
   *
   * Returns the updated writ document.
   */
  setWritStatus(writId: string, pluginId: string, value: unknown): Promise<WritDoc>;

  /**
   * Write a plugin-owned sub-slot of the writ's metadata `ext` map.
   *
   * The slot is the metadata sibling to `status`: plugins attach
   * metadata-shape data here (petition ids, cross-references,
   * classifier tags, configuration extensions) — data that belongs to
   * the writ as an attribute of its identity, rather than the post-hoc
   * observation `setWritStatus` records.
   *
   * The call is a transactional read-modify-write — the sub-slot keyed by
   * `pluginId` is replaced with `value`, but sibling sub-slots owned by
   * other plugins are preserved. Writes emit CDC update events like any
   * other field change, and survive terminal phase transitions.
   *
   * Validation: throws when `writId` is empty, when `pluginId` is empty,
   * or when no writ matches `writId`. The `value` is opaque — the Clerk
   * does not validate sub-slot contents (mirrors `setWritStatus`).
   *
   * Each call bumps `updatedAt` to the current ISO timestamp so CDC
   * observers keying on the timestamp see the change.
   *
   * Ownership is convention-only: plugin `X` writes only `ext[X]`.
   * There is no runtime guard.
   *
   * Returns the updated writ document.
   */
  setWritExt(writId: string, pluginId: string, value: unknown): Promise<WritDoc>;

  /**
   * Create a typed directional link from one writ to another.
   * Both writs must exist. Self-links are rejected. The `label` argument is
   * normalized before the composite id is constructed, so variant spellings
   * of the same label collapse to a single link. When a link with the same
   * canonical composite id already exists, the existing row is returned;
   * if `kind` is supplied, it is written onto the existing row (upsert). The
   * optional `kind` must reference an id registered in the kit-contributed
   * link-kind registry; unknown ids are rejected.
   */
  link(
    sourceId: string,
    targetId: string,
    label: string,
    kind?: string,
  ): Promise<WritLinkDoc>;

  /**
   * Query all links for a writ — both outbound (this writ is the source)
   * and inbound (this writ is the target).
   */
  links(writId: string): Promise<WritLinks>;

  /**
   * Remove a link. Idempotent — no error if the link does not exist.
   */
  unlink(sourceId: string, targetId: string, label: string): Promise<void>;

  /**
   * Edit a writ. Title and body can be edited in any status.
   * Type and codex can only be changed while the writ is in 'new' status.
   * Only the provided fields are updated. Validates type against
   * declared writ types if provided.
   */
  edit(request: EditWritRequest): Promise<WritDoc>;

  /**
   * List the writ types registered with the Clerk via `registerWritType`,
   * including the Clerk's own built-in `mandate`. Each entry reports the
   * name, the (currently-always-null) description, source (`builtin` or
   * `plugin`), and whether it is the default type.
   */
  listWritTypes(): WritTypeInfo[];

  /**
   * List all registered link kinds contributed by kits.
   * Returns the registry-projection view of each kind, including its owner
   * plugin id. Returns an empty array when no kinds have been registered.
   */
  listKinds(): Promise<LinkKindDoc[]>;

  /**
   * Register a writ type's state machine with the Clerk.
   *
   * The supplied config is validated via `validateWritTypeConfig` before the
   * registry is updated; validator errors propagate verbatim. Registration-
   * specific failures (duplicate name, late call after the startup window has
   * sealed) are wrapped with a `[clerk] registerWritType:` prefix.
   *
   * Callable only while the startup window is open — Clerk seals the
   * registry on the framework's global `phase:started` signal, after which
   * further calls throw. This is the single-surface entry point for plugins
   * contributing writ types; there is no parallel kit-channel or guild-config
   * registration path.
   */
  registerWritType(config: WritTypeConfig): void;

  /**
   * Return the registered `WritTypeConfig` for a writ type.
   *
   * Returns `undefined` when the name is not registered. Callers that need
   * to work with a writ type abstractly (inspect states, render UI labels,
   * compose higher-level predicates) should use this accessor instead of
   * reaching into the predicate surface with synthetic `WritDoc`s.
   */
  getWritTypeConfig(name: string): WritTypeConfig | undefined;

  /**
   * Return `true` when the writ's current state is classified `initial`
   * in its type's registered config.
   *
   * Throws when the writ's stored state is not declared in its type config
   * (fail-loud on unknown-state), or when the writ's type is not registered.
   */
  isInitial(writ: WritDoc): boolean;

  /**
   * Return `true` when the writ's current state is classified `active`
   * in its type's registered config.
   *
   * Throws when the writ's stored state is not declared in its type config
   * (fail-loud on unknown-state), or when the writ's type is not registered.
   */
  isActive(writ: WritDoc): boolean;

  /**
   * Return `true` when the writ's current state is classified `terminal`
   * in its type's registered config.
   *
   * Throws when the writ's stored state is not declared in its type config
   * (fail-loud on unknown-state), or when the writ's type is not registered.
   */
  isTerminal(writ: WritDoc): boolean;
}

