import { z } from 'zod';
import { guild } from '@shardworks/nexus-core';
import { tool } from '@shardworks/tools-apparatus';
import type { CartographApi } from '../types.ts';
import type { ClerkApi } from '@shardworks/clerk-apparatus';

/**
 * Patch a vision's companion doc. Per D6 the only mutable companion-doc
 * field today is `codex` — title/body live on the writ row and are edited
 * via `nsg writ edit`. Per D5 the `--stage` flag is intentionally absent;
 * stage transitions go through `vision-transition` so the writ phase and
 * the doc stage stay coupled in one transaction.
 */
export default tool({
  name: 'vision-patch',
  description: "Patch a vision's companion doc",
  instructions:
    "Updates a vision's companion doc. The only patchable field today is `codex`. " +
    'Title/body live on the writ row — edit them via `nsg writ edit`. Stage updates go ' +
    'through `vision-transition` so the writ phase and the companion stage move in one ' +
    'atomic step.',
  params: {
    id: z.string().describe('Vision id (or short prefix)'),
    codex: z.string().optional().describe('New target codex (empty string to clear)'),
  },
  permission: 'write',
  callableBy: ['patron'],
  handler: async (params) => {
    if (params.codex === undefined) {
      throw new Error('vision-patch requires at least one mutable field (currently `--codex`).');
    }
    const cartograph = guild().apparatus<CartographApi>('cartograph');
    const clerk = guild().apparatus<ClerkApi>('clerk');
    const resolvedId = await clerk.resolveId(params.id);
    return cartograph.patchVision(resolvedId, {
      codex: params.codex,
      updatedAt: new Date().toISOString(),
    });
  },
});

import { z } from 'zod';
import { guild } from '@shardworks/nexus-core';
import { tool } from '@shardworks/tools-apparatus';
import type { CartographApi } from '../types.ts';
import type { ClerkApi } from '@shardworks/clerk-apparatus';

/**
 * Allowed writ phases across all writ types (mirrors `WritPhase` from
 * the Clerk API). Required at the Zod boundary so `--help` enumerates
 * the legal values (D16). The typed API still enforces per-state
 * `allowedTransitions` and rejects illegal edges.
 */
const WRIT_PHASES = ['new', 'open', 'stuck', 'completed', 'failed', 'cancelled'] as const;

/**
 * Vision-specific stage enum (mirrors `VisionStage` from `../types.ts`).
 * Per D15 the caller supplies both phase and stage explicitly because a
 * single phase may map to multiple stages depending on context.
 */
const VISION_STAGES = ['draft', 'active', 'sunset', 'cancelled'] as const;

/**
 * Transition a vision: writes both `writ.phase` and the companion doc's
 * `stage` atomically inside one Stacks transaction. Both `--phase` and
 * `--stage` are required (D15) and Zod-enum-validated (D16). Optional
 * `--resolution` lands in the same transaction (D17).
 */
export default tool({
  name: 'vision-transition',
  description: 'Transition a vision lifecycle (writes phase + stage atomically)',
  instructions:
    'Atomically updates the vision writ\'s phase and the companion doc\'s stage. ' +
    'Both --phase and --stage are required: a single phase may map to multiple ' +
    'stages depending on context (e.g. failed → cancelled vs failed → sunset). ' +
    'The typed API rejects illegal phase edges per the writ-type config.',
  params: {
    id: z.string().describe('Vision id (or short prefix)'),
    phase: z.enum(WRIT_PHASES).describe('Target phase on the underlying writ'),
    stage: z.enum(VISION_STAGES).describe('Target stage on the companion vision doc'),
    resolution: z
      .string()
      .optional()
      .describe('Optional resolution string. Recorded on terminal transitions.'),
  },
  permission: 'write',
  callableBy: ['patron'],
  handler: async (params) => {
    const cartograph = guild().apparatus<CartographApi>('cartograph');
    const clerk = guild().apparatus<ClerkApi>('clerk');
    const resolvedId = await clerk.resolveId(params.id);
    return cartograph.transitionVision(resolvedId, {
      phase: params.phase,
      stage: params.stage,
      ...(params.resolution !== undefined ? { resolution: params.resolution } : {}),
    });
  },
});

