1	/**
2	 * vision-apply — integration tests with real filesystem round-trips.
3	 *
4	 * Uses a `mkdtemp`-backed fakeGuild `home` so vision.md and the sidecar
5	 * round-trip on disk (D17). Wires real stacks + clerk + cartograph
6	 * exactly like cartograph.test.ts so the apply tool exercises the
7	 * production code paths through `tool.handler({...})` directly.
8	 *
9	 * Coverage:
10	 *   - First-apply happy path (writ + doc created, sidecar gains
11	 *     visionId, exactly one CDC event on the cartograph visions book).
12	 *   - Nth-apply happy path (writ resolved via visionId, body and
13	 *     stage/codex synced, single CDC event).
14	 *   - CLI flag overrides sidecar for severity/deadline/decay.
15	 *   - Stale-binding errors: missing, cancelled, completed, failed.
16	 *   - Missing vision.md or sidecar errors.
17	 *   - Malformed sidecar errors.
18	 *   - sunset / cancelled initial stage rejection.
19	 *   - Bad-slug rejection (path separators, leading dots, "..").
20	 *   - ext['surveyor'] payload shape per merge rule.
21	 *   - Comments and key order in the sidecar survive the visionId
22	 *     round-trip write-back.
23	 *   - Resolution flows through on terminal Nth-apply transitions.
24	 */
25	
26	import { describe, it, beforeEach, afterEach } from 'node:test';
27	import assert from 'node:assert/strict';
28	import { mkdtemp, rm, mkdir, writeFile, readFile } from 'node:fs/promises';
29	import { tmpdir } from 'node:os';
30	import path from 'node:path';
31	
32	import { setGuild, clearGuild } from '@shardworks/nexus-core';
33	import type {
34	  Guild,
35	  GuildConfig,
36	  LoadedApparatus,
37	  LoadedKit,
38	  StartupContext,
39	} from '@shardworks/nexus-core';
40	
41	import { createStacksApparatus } from '@shardworks/stacks-apparatus';
42	import { MemoryBackend } from '@shardworks/stacks-apparatus/testing';
43	import type { StacksApi } from '@shardworks/stacks-apparatus';
44	
45	import { createClerk } from '@shardworks/clerk-apparatus';
46	import type { ClerkApi, WritDoc } from '@shardworks/clerk-apparatus';
47	
48	import { createCartograph } from '../cartograph.ts';
49	import type { CartographApi, VisionDoc } from '../types.ts';
50	
51	import visionApply, { SURVEYOR_PLUGIN_ID } from './vision-apply.ts';
52	
53	// ── Fixture ──────────────────────────────────────────────────────────
54	
55	interface Fixture {
56	  stacks: StacksApi;
57	  clerk: ClerkApi;
58	  cartograph: CartographApi;
59	  memBackend: MemoryBackend;
60	  home: string;
61	  // Live counter of CDC events on the cartograph visions book.
62	  cdc: { create: number; update: number; delete: number };
63	}
64	
65	function buildCtx(): StartupContext {
66	  return {
67	    on(): void {},
68	    kits(): never[] {
69	      return [];
70	    },
71	  };
72	}
73	
74	async function buildFixture(): Promise<Fixture> {
75	  const home = await mkdtemp(path.join(tmpdir(), 'cartograph-vision-apply-'));
76	
77	  const memBackend = new MemoryBackend();
78	  const stacksPlugin = createStacksApparatus(memBackend);
79	  const clerkPlugin = createClerk();
80	  const cartographPlugin = createCartograph();
81	
82	  const apparatusMap = new Map<string, unknown>();
83	
84	  const fakeGuildConfig: GuildConfig = {
85	    name: 'cartograph-vision-apply-guild',
86	    nexus: '0.0.0',
87	    plugins: [],
88	  };
89	
90	  const fakeGuild: Guild = {
91	    home,
92	    apparatus<T>(name: string): T {
93	      const a = apparatusMap.get(name);
94	      if (!a) throw new Error(`Apparatus "${name}" not installed`);
95	      return a as T;
96	    },
97	    tryApparatus<T>(name: string): T | null {
98	      try { return this.apparatus<T>(name); } catch { return null; }
99	    },
100	    config<T>(_pluginId: string): T {
101	      return {} as T;
102	    },
103	    writeConfig(): void {},
104	    guildConfig(): GuildConfig {
105	      return fakeGuildConfig;
106	    },
107	    kits(): LoadedKit[] {
108	      return [];
109	    },
110	    apparatuses(): LoadedApparatus[] {
111	      return [];
112	    },
113	    failedPlugins() {
114	      return [];
115	    },
116	    startupWarnings(): string[] {
117	      return [];
118	    },
119	  };
120	  setGuild(fakeGuild);
121	
122	  // Stacks
123	  stacksPlugin.apparatus.start!(buildCtx());
124	  const stacks = stacksPlugin.apparatus.provides as StacksApi;
125	  apparatusMap.set('stacks', stacks);
126	
127	  memBackend.ensureBook({ ownerId: 'clerk', book: 'writs' }, {
128	    indexes: [
129	      'phase', 'type', 'createdAt', 'parentId',
130	      ['phase', 'type'], ['phase', 'createdAt'], ['parentId', 'phase'],
131	    ],
132	  });
133	  memBackend.ensureBook({ ownerId: 'clerk', book: 'links' }, {
134	    indexes: [
135	      'sourceId', 'targetId', 'label',
136	      ['sourceId', 'label'], ['targetId', 'label'],
137	    ],
138	  });
139	  memBackend.ensureBook({ ownerId: 'cartograph', book: 'visions' }, {
140	    indexes: ['stage', 'codex', 'createdAt'],
141	  });
142	  memBackend.ensureBook({ ownerId: 'cartograph', book: 'charges' }, {
143	    indexes: ['stage', 'codex', 'createdAt'],
144	  });
145	  memBackend.ensureBook({ ownerId: 'cartograph', book: 'pieces' }, {
146	    indexes: ['stage', 'codex', 'createdAt'],
147	  });
148	
149	  // Clerk
150	  await clerkPlugin.apparatus.start!(buildCtx());
151	  const clerk = clerkPlugin.apparatus.provides as ClerkApi;
152	  apparatusMap.set('clerk', clerk);
153	
154	  // Cartograph
155	  await cartographPlugin.apparatus.start!(buildCtx());
156	  const cartograph = cartographPlugin.apparatus.provides as CartographApi;
157	  apparatusMap.set('cartograph', cartograph);
158	
159	  // CDC counter — register before any writes so we observe the very
160	  // first create event from the first apply.
161	  const cdc = { create: 0, update: 0, delete: 0 };
162	  stacks.watch<VisionDoc>('cartograph', 'visions', (event) => {
163	    if (event.type === 'create') cdc.create += 1;
164	    if (event.type === 'update') cdc.update += 1;
165	    if (event.type === 'delete') cdc.delete += 1;
166	  });
167	
168	  return { stacks, clerk, cartograph, memBackend, home, cdc };
169	}
170	
171	async function teardown(fix: Fixture): Promise<void> {
172	  clearGuild();
173	  await rm(fix.home, { recursive: true, force: true });
174	}
175	
176	/** Materialize a vision dir at `<home>/vision/<slug>/` with the given files. */
177	async function writeVisionDir(
178	  home: string,
179	  slug: string,
180	  contents: { visionMd?: string | null; sidecar?: string | null },
181	): Promise<{ visionDir: string; visionMdPath: string; sidecarPath: string }> {
182	  const visionDir = path.join(home, 'vision', slug);
183	  await mkdir(visionDir, { recursive: true });
184	  const visionMdPath = path.join(visionDir, 'vision.md');
185	  const sidecarPath = path.join(visionDir, 'vision-metadata.yml');
186	  if (contents.visionMd !== null && contents.visionMd !== undefined) {
187	    await writeFile(visionMdPath, contents.visionMd, 'utf8');
188	  }
189	  if (contents.sidecar !== null && contents.sidecar !== undefined) {
190	    await writeFile(sidecarPath, contents.sidecar, 'utf8');
191	  }
192	  return { visionDir, visionMdPath, sidecarPath };
193	}
194	
195	// ── Tests ────────────────────────────────────────────────────────────
196	
197	describe('vision-apply tool', () => {
198	  let fix: Fixture;
199	
200	  beforeEach(async () => {
201	    fix = await buildFixture();
202	  });
203	
204	  afterEach(async () => {
205	    await teardown(fix);
206	  });
207	
208	  // ── First apply happy path ───────────────────────────────────────
209	
210	  describe('first apply — bootstrap', () => {
211	    it('creates a vision writ + VisionDoc, writes ext[surveyor], writes visionId back to sidecar', async () => {
212	      await writeVisionDir(fix.home, 'my-vision', {
213	        visionMd: '# Land the ladder\n\nLong-form vision text here.',
214	        sidecar:
215	          'title: Land the ladder\n' +
216	          'stage: draft\n' +
217	          'codex: main\n' +
218	          'severity: high\n',
