221	      const result = await visionApply.handler({ slug: 'my-vision' }) as VisionDoc;
222	
223	      // Companion doc was created.
224	      assert.ok(result.id.startsWith('w-'));
225	      assert.equal(result.stage, 'draft');
226	      assert.equal(result.codex, 'main');
227	
228	      // Underlying writ has the right type/phase/title/body/codex.
229	      const writ = await fix.clerk.show(result.id);
230	      assert.equal(writ.type, 'vision');
