233	      assert.equal(writ.body, '# Land the ladder\n\nLong-form vision text here.');
234	      assert.equal(writ.codex, 'main');
235	
236	      // Surveyor ext slot was written with severity from sidecar.
237	      assert.deepEqual(writ.ext?.[SURVEYOR_PLUGIN_ID], { severity: 'high' });
238	
239	      // Exactly one CDC event on the cartograph visions book — the
240	      // single-event-per-apply contract.
241	      assert.equal(fix.cdc.create, 1);
242	      assert.equal(fix.cdc.update, 0);
243	
244	      // Sidecar gained the visionId binding.
245	      const sidecarPath = path.join(fix.home, 'vision', 'my-vision', 'vision-metadata.yml');
246	      const updatedSidecar = await readFile(sidecarPath, 'utf8');
247	      assert.match(updatedSidecar, /visionId:/);
